### 2. The tiny OCaml wrapper – `pcapng.ml`

```ocaml
(*--------------------------------------------------------------------
   pcapng.ml – thin OCaml wrappers around the C stubs
  --------------------------------------------------------------------*)

external open_file : string -> t = "pcapng_open_file"
external close      : t -> unit = "pcapng_close"

external iter : (frame -> bool) -> t -> unit = "pcapng_iter"

external captured_len : frame -> int = "pcapng_captured_len"
external original_len : frame -> int = "pcapng_original_len"
external timestamp    : frame -> int64 = "pcapng_timestamp"

external data_bigarray : frame ->
  (char, Bigarray.int8_unsigned_elt, Bigarray.c_layout) Bigarray.Array1.t
  = "pcapng_data_bigarray"

external data : frame -> bytes = "pcapng_data"
