### 3. The C++ implementation – `pcapng_stubs.cpp`

```cpp
/*--------------------------------------------------------------------
   pcapng_stubs.cpp – C++ stubs for OCaml
   Compile with:   ocamlc -c -I +bigarray pcapng_stubs.cpp
   Link with:      -lpcapng -lstdc++
  --------------------------------------------------------------------*/

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/bigarray.h>

#include <pcapng.h>          // libpcapng public header
#include <cstdint>
#include <cstring>

/* ------------------------------------------------------------------ */
/*  OCaml representation of the opened file                           */
/* ------------------------------------------------------------------ */
typedef struct {
    pcapng::File *file;   // owned by us
} caml_pcapng_file;

/* custom operations for the file handle --------------------------------*/
static void caml_pcapng_file_finalize(value v) {
    caml_pcapng_file *pf = (caml_pcapng_file *)Data_custom_val(v);
    if (pf->file) {
        delete pf->file;
        pf->file = nullptr;
    }
}
static struct custom_operations caml_pcapng_file_ops = {
    "pcapng.file",
    caml_pcapng_file_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* ------------------------------------------------------------------ */
/*  OCaml representation of a single frame (the “view”)                */
/* ------------------------------------------------------------------ */
typedef struct {
    const pcapng::Block *block;   // points to the current block
} caml_pcapng_frame;

/* custom ops for the frame – no finalizer needed (no allocation) -----*/
static void caml_pcapng_frame_finalize(value) {}
static struct custom_operations caml_pcapng_frame_ops = {
    "pcapng.frame",
    caml_pcapng_frame_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* ------------------------------------------------------------------ */
/*  Helper: allocate a new OCaml file value                               */
/* ------------------------------------------------------------------ */
static value alloc_pcapng_file(pcapng::File *f) {
    value v = caml_alloc_custom(&caml_pcapng_file_ops,
                               sizeof(caml_pcapng_file), 0, 1);
    caml_pcapng_file *pf = (caml_pcapng_file *)Data_custom_val(v);
    pf->file = f;
    return v;
}

/* ------------------------------------------------------------------ */
/*  Helper: allocate a frame value (once, then we will mutate its ptr)   */
/* ------------------------------------------------------------------ */
static value alloc_pcapng_frame() {
    value v = caml_alloc_custom(&caml_pcapng_frame_ops,
                               sizeof(caml_pcapng_frame), 0, 0);
    caml_pcapng_frame *pf = (caml_pcapng_frame *)Data_custom_val(v);
    pf->block = nullptr;          // will be filled later
    return v;
}

/* ------------------------------------------------------------------ */
/*  OCaml primitives                                                    */
/* ------------------------------------------------------------------ */

/* open_file : string -> t */
extern "C" CAMLprim value pcapng_open_file(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_res);
    const char *path = String_val(v_path);
    try {
        pcapng::File *f = new pcapng::File(path);
        v_res = alloc_pcapng_file(f);
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    }
    CAMLreturn(v_res);
}

/* close : t -> unit */
extern "C" CAMLprim value pcapng_close(value v_file) {
    CAMLparam1(v_file);
    caml_pcapng_file *pf = (caml_pcapng_file *)Data_custom_val(v_file);
    if (pf->file) {
        delete pf->file;
        pf->file = nullptr;
    }
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------ */
/*  iter : (frame -> bool) -> t -> unit                                 */
/* ------------------------------------------------------------------ */
extern "C" CAMLprim value pcapng_iter(value v_cb, value v_file) {
    CAMLparam2(v_cb, v_file);
    caml_pcapng_file *pf = (caml_pcapng_file *)Data_custom_val(v_file);
    if (!pf->file) caml_failwith("pcapng: file already closed");

    /* Allocate a single frame value that we will reuse */
    value v_frame = alloc_pcapng_frame();
    caml_pcapng_frame *pframe = (caml_pcapng_frame *)Data_custom_val(v_frame);

    try {
        for (auto it = pf->file->begin(); it != pf->file->end(); ++it) {
            const pcapng::Block &blk = *it;
            /* libpcapng only yields Enhanced Packet Blocks (EPB) for
               actual frames.  We ignore any other block types. */
            if (blk.get_type() != pcapng::Block::ENHANCED_PACKET) continue;

            pframe->block = &blk;               // update pointer in‑place
            /* Call the OCaml callback */
            int keep = Bool_val(caml_callback(v_cb, v_frame));
            if (!keep) break;                   // early abort requested
        }
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    }
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------ */
/*  Primitive accessors on a frame                                      */
/* ------------------------------------------------------------------ */
static const pcapng::EnhancedPacketBlock *
get_epb(const caml_pcapng_frame *pframe) {
    const pcapng::Block *blk = pframe->block;
    if (!blk) caml_failwith("pcapng: uninitialized frame");
    if (blk->get_type() != pcapng::Block::ENHANCED_PACKET)
        caml_failwith("pcapng: unexpected block type");
    return static_cast<const pcapng::EnhancedPacketBlock *>(blk);
}

/* captured_len : frame -> int */
extern "C" CAMLprim value pcapng_captured_len(value v_frame) {
    CAMLparam1(v_frame);
    const caml_pcapng_frame *pframe = (caml_pcapng_frame *)Data_custom_val(v_frame);
    const pcapng::EnhancedPacketBlock *epb = get_epb(pframe);
    CAMLreturn(Val_int(epb->get_captured_len()));
}

/* original_len : frame -> int */
extern "C" CAMLprim value pcapng_original_len(value v_frame) {
    CAMLparam1(v_frame);
    const caml_pcapng_frame *pframe = (caml_pcapng_frame *)Data_custom_val(v_frame);
    const pcapng::EnhancedPacketBlock *epb = get_epb(pframe);
    CAMLreturn(Val_int(epb->get_original_len()));
}

/* timestamp : frame -> int64 */
extern "C" CAMLprim value pcapng_timestamp(value v_frame) {
    CAMLparam1(v_frame);
    const caml_pcapng_frame *pframe = (caml_pcapng_frame *)Data_custom_val(v_frame);
    const pcapng::EnhancedPacketBlock *epb = get_epb(pframe);
    /* libpcapng stores timestamp as seconds + nanoseconds.  OCaml wants
       a 64‑bit integer representing seconds since epoch. */
    uint64_t sec = epb->get_timestamp_high();   // seconds part
    uint64_t nsec = epb->get_timestamp_low();   // nanoseconds part
    int64_t ocaml_ts = (int64_t)sec;            // ignore sub‑second for simplicity
    CAMLreturn(caml_copy_int64(ocaml_ts));
}

/* data_bigarray : frame -> bigarray */
extern "C" CAMLprim value pcapng_data_bigarray(value v_frame) {
    CAMLparam1(v_frame);
    const caml_pcapng_frame *pframe = (caml_pcapng_frame *)Data_custom_val(v_frame);
    const pcapng::EnhancedPacketBlock *epb = get_epb(pframe);
    const uint8_t *data = epb->get_packet_data();
    size_t len = epb->get_captured_len();

    /* Build a bigarray that points directly at the libpcapng buffer.
       The bigarray is a lightweight OCaml value; no copy is performed. */
    intnat dims[1] = { (intnat)len };
    value v_ba = caml_ba_alloc(CAML_BA_UINT8 | CAML_BA_C_LAYOUT,
                               1, (char *)data, dims);
    CAMLreturn(v_ba);
}

/* data : frame -> bytes   (copy) */
extern "C" CAMLprim value pcapng_data(value v_frame) {
    CAMLparam1(v_frame);
    const caml_pcapng_frame *pframe = (caml_pcapng_frame *)Data_custom_val(v_frame);
    const pcapng::EnhancedPacketBlock *epb = get_epb(pframe);
    const uint8_t *src = epb->get_packet_data();
    size_t len = epb->get_captured_len();

    value v_bytes = caml_alloc_string(len);
    memcpy(String_val(v_bytes), src, len);
    CAMLreturn(v_bytes);
}

/* ------------------------------------------------------------------ */
/*  Registration of the primitives (optional, but nice for ocamlc)      */
/* ------------------------------------------------------------------ */
#if defined(CAML_EXPORT)
CAML_EXPORT
#else
#define CAML_EXPORT
#endif

CAML_EXPORT void caml_pcapng_init(void) {
    /* Nothing to do – the functions are exported via the extern "C"
       symbols above.  The entry point is kept for compatibility with
       the OCaml runtime. */
}
```

--------------------------------------------------------------------
### 4. Build instructions (a minimal Makefile‑style snippet)

```make
# --------------------------------------------------------------
# Build the OCaml binding (requires libpcapng and a C++ compiler)
# --------------------------------------------------------------

OCAMLFLAGS = -thread -I +bigarray
CXXFLAGS   = -O3 -Wall -fPIC $(shell ocamlc -where)/caml
LIBS       = -lpcapng -lstdc++

all: libpcapng_stubs.o libpcapng.cma

# Compile the C++ stub (produces a .o that OCaml can link)
libpcapng_stubs.o: pcapng_stubs.cpp
	$(CXX) $(CXXFLAGS) -c $< -o $@

# Build a bytecode library (optional)
libpcapng.cma: pcapng.cmo
	ocamlc -a -o $@ $^

# Build a native library (recommended for the hot path)
libpcapng.cmxa: pcapng.cmx
	ocamlopt -a -o $@ $^

# Compile the OCaml files
pcapng.cmo: pcapng.ml pcapng.mli
	ocamlc $(OCAMLFLAGS) -c pcapng.ml

pcapng.cmx: pcapng.ml pcapng.mli
	ocamlopt $(OCAMLFLAGS) -c pcapng.ml

clean:
	rm -f *.cmi *.cmo *.cmx *.o *.cmxa *.cma

.PHONY: all clean
```

*Compile with*  

```sh
make            # builds libpcapng_stubs.o and libpcapng.cmxa
```

Then link your program with the generated native library, e.g.

```sh
ocamlopt -I +bigarray unix.cmxa libpcapng.cmxa my_program.ml -o my_program
```

--------------------------------------------------------------------
### 5. How the hot‑path works (why it is fast)

| Step | What happens | Allocation? |
|------|--------------|-------------|
| **File open** | `pcapng_open_file` creates a C++ `pcapng::File` object, stored inside a custom OCaml block. | One custom block (once). |
| **Iter start** | `pcapng_iter` allocates **one** `frame` custom block (`v_frame`). | One custom block (once). |
| **Loop** | For each underlying libpcapng frame: <br>1. Update `pframe->block` pointer in the custom block.<br>2. Call the user callback (`caml_callback`). | **Zero** per‑frame allocation. |
| **Callback** | The OCaml code reads fields via the accessor primitives. <br>*Reading primitive fields* (`captured_len`, `original_len`, `timestamp`) just dereferences the pointer – O(1). <br>*Zero‑copy access* (`data_bigarray`) builds a tiny bigarray value that just wraps the raw pointer (allocation of a bigarray header, ~16 bytes). <br>*Copy* (`data`) copies the payload into a fresh `bytes` only if the user explicitly asks for it. | At most one small bigarray per callback (optional). |
| **Early abort** | If the OCaml callback returns `false`, the C++ loop breaks immediately – no extra work. | – |
| **File close** | `pcapng_close` deletes the C++ `File` object; the custom block’s finalizer does the same. | – |

Thus the only per‑frame cost is the **callback dispatch** (which is unavoidable) plus a handful of pointer dereferences. No per‑frame heap allocation, no data copying, and the heavy lifting stays in C++ where the original library is already optimised.

