### 6. Example usage (OCaml side)

```ocaml
let () =
  let p = Pcapng.open_file "huge_capture.pcapng" in
  (* Count how many Ethernet frames contain a given EtherType *)
  let target = 0x0800 (* IPv4 *) in
  let count = ref 0 in
  let continue _frame =    (* callback – runs 800 million times *)
    (* fast primitive access, no copies *)
    let data = Pcapng.data_bigarray _frame in
    if Bigarray.Array1.dim data >= 14 then
      let eth_type = (Char.code (Bigarray.Array1.get data 12) lsl 8)
                     lor (Char.code (Bigarray.Array1.get data 13)) in
